using_admin_sdk.code:
const admin = require('firebase-admin');

// Initialize Firebase Admin SDK
const serviceAccount = require('./path/to/serviceAccountKey.json');
admin.initializeApp({
  credential: admin.credential.cert(serviceAccount)
});

// Send notification function
async function sendNotification(deviceToken, notificationData) {
  const message = {
    token: deviceToken,
    notification: {
      title: notificationData.title,
      body: notificationData.body
    },
    data: {
      type: 'navigate',
      screen: notificationData.screen || 'HomeScreen',
      category: notificationData.category || 'update',
      description: notificationData.description || '',
      createdAt: new Date().toISOString(),
      notificationId: notificationData.id || Date.now().toString()
    },
    android: {
      priority: 'high',
      notification: {
        icon: 'ic_notification',
        color: getColorForCategory(notificationData.category),
        sound: 'default'
      }
    },
    apns: {
      payload: {
        aps: {
          alert: {
            title: notificationData.title,
            body: notificationData.body
          },
          sound: 'default',
          badge: 1
        }
      }
    }
  };

  try {
    const response = await admin.messaging().send(message);
    console.log('Successfully sent message:', response);
    return response;
  } catch (error) {
    console.log('Error sending message:', error);
    throw error;
  }
}

// Helper function to get color based on category
function getColorForCategory(category) {
  const colors = {
    'promotion': '#FF9800',
    'transaction': '#4CAF50',
    'alert': '#F44336',
    'update': '#2196F3',
    'request': '#9C27B0'
  };
  return colors[category] || '#2196F3';
}

// Usage examples
sendNotification('DEVICE_TOKEN_HERE', {
  title: '🍊 New Offer',
  body: 'Get 10% off on oranges today!',
  category: 'promotion',
  screen: 'HomeScreen',
  description: 'Special discount on fresh oranges',
  id: 'promo_001'
});

sendNotification('DEVICE_TOKEN_HERE', {
  title: 'Request Accepted',
  body: 'Your request for Banana has been accepted by farmer John',
  category: 'request',
  screen: 'MyOrdersScreen',
  description: 'Navigate to orders',
  id: 'req_001'
});
